Here’s a simple example of refactoring a messy function:
python
def calculate_discount(price, is_member, has_coupon):
    # Original messy logic
    if price > 100:
        if is_member:
            if has_coupon:
                return price * 0.7
            else:
                return price * 0.8
        else:
            return price * 0.9
    else:
        if is_member:
            return price * 0.95
        else:
            return price

# Refactored version
DISCOUNT_MEMBER = 0.8
DISCOUNT_NON_MEMBER = 0.9
DISCOUNT_COUPON = 0.7

DISCOUNT_THRESHOLD = 100

DISCOUNT_LOW_MEMBER = 0.95

def calculate_discount(price, is_member, has_coupon):
    base_discount = DISCOUNT_LOW_MEMBER if price <= DISCOUNT_THRESHOLD and is_member else (
        DISCOUNT_COUPON if has_coupon else DISCOUNT_MEMBER if is_member else DISCOUNT_NON_MEMBER
    )
    return price * base_discount
